-- 删除测试城市的合伙人配置
DELETE FROM partner_cities WHERE cityId IN (SELECT id FROM cities WHERE name LIKE '测试%');

-- 删除测试城市的费用账单
DELETE FROM city_monthly_expenses WHERE cityId IN (SELECT id FROM cities WHERE name LIKE '测试%');

-- 删除测试城市
DELETE FROM cities WHERE name LIKE '测试%';

